('business:6-2-the-economic-climate:match:bcbc97f9', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Consumer income”?", "options": ["The total amount of income all customers in the country receive and have available to spend.", "The number of people out of work in a country.", "The number of people in work in a country.", "A measure of how much a country produces in a year; influences income and employment levels."]}'::jsonb, '{"answer": 0, "explain": "“Consumer income” means: The total amount of income all customers in the country receive and have available to spend."}'::jsonb),
('business:6-2-the-economic-climate:match:97e52be1', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Level of unemployment”?", "options": ["The number of people in work in a country.", "A measure of how much a country produces in a year; influences income and employment levels.", "A period when GDP is rising, causing income and employment to rise.", "The number of people out of work in a country."]}'::jsonb, '{"answer": 3, "explain": "“Level of unemployment” means: The number of people out of work in a country."}'::jsonb),
('business:6-2-the-economic-climate:match:c515ca48', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Level of employment”?", "options": ["The number of people in work in a country.", "A measure of how much a country produces in a year; influences income and employment levels.", "A period when GDP is rising, causing income and employment to rise.", "A period when GDP is falling, causing income and employment to fall."]}'::jsonb, '{"answer": 0, "explain": "“Level of employment” means: The number of people in work in a country."}'::jsonb),
('business:6-2-the-economic-climate:match:09f80e12', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “GDP”?", "options": ["A measure of how much a country produces in a year; influences income and employment levels.", "A period when GDP is rising, causing income and employment to rise.", "A period when GDP is falling, causing income and employment to fall.", "How income is shared out among different people in the community."]}'::jsonb, '{"answer": 0, "explain": "“GDP” means: A measure of how much a country produces in a year; influences income and employment levels."}'::jsonb),
('business:6-2-the-economic-climate:match:26b921ac', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Economic growth”?", "options": ["A period when GDP is falling, causing income and employment to fall.", "A period when GDP is rising, causing income and employment to rise.", "How income is shared out among different people in the community.", "What is happening to income and employment in different parts of the world."]}'::jsonb, '{"answer": 1, "explain": "“Economic growth” means: A period when GDP is rising, causing income and employment to rise."}'::jsonb),
('business:6-2-the-economic-climate:match:f0ba90ac', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Recession”?", "options": ["A period when GDP is falling, causing income and employment to fall.", "How income is shared out among different people in the community.", "What is happening to income and employment in different parts of the world.", "A period when income and employment are rising, generally good for most businesses."]}'::jsonb, '{"answer": 0, "explain": "“Recession” means: A period when GDP is falling, causing income and employment to fall."}'::jsonb),
('business:6-2-the-economic-climate:match:9f5e68b6', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Distribution of income”?", "options": ["What is happening to income and employment in different parts of the world.", "How income is shared out among different people in the community.", "A period when income and employment are rising, generally good for most businesses.", "A period when income and employment are falling, generally bad for most businesses."]}'::jsonb, '{"answer": 1, "explain": "“Distribution of income” means: How income is shared out among different people in the community."}'::jsonb),
('business:6-2-the-economic-climate:match:2f5c1e46', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “International economic climate”?", "options": ["A period when income and employment are rising, generally good for most businesses.", "What is happening to income and employment in different parts of the world.", "A period when income and employment are falling, generally bad for most businesses.", "How well the country is doing in terms of the levels of income and employment."]}'::jsonb, '{"answer": 1, "explain": "“International economic climate” means: What is happening to income and employment in different parts of the world."}'::jsonb),
('business:6-2-the-economic-climate:match:1f3b0292', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Favourable economic climate”?", "options": ["A period when income and employment are rising, generally good for most businesses.", "A period when income and employment are falling, generally bad for most businesses.", "How well the country is doing in terms of the levels of income and employment.", "The amount of money people receive from work and from assets such as shares and property."]}'::jsonb, '{"answer": 0, "explain": "“Favourable economic climate” means: A period when income and employment are rising, generally good for most businesses."}'::jsonb),
('business:6-2-the-economic-climate:match:da33da24', 'business', 'business:6-2-the-economic-climate', '6.2 The Economic Climate', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Unfavourable economic climate”?", "options": ["How well the country is doing in terms of the levels of income and employment.", "The amount of money people receive from work and from assets such as shares and property.", "The total amount of income all customers in the country receive and have available to spend.", "A period when income and employment are falling, generally bad for most businesses."]}'::jsonb, '{"answer": 3, "explain": "“Unfavourable economic climate” means: A period when income and employment are falling, generally bad for most businesses."}'::jsonb),
('business:6-3-globalisation:exam:06e085de', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'exam', 'mcq', 1, '{"num": "Q1", "question": "What has <strong>not</strong> contributed to increased globalisation?", "options": ["A reduction in shipping costs due to bulk containerisation", "An increase in labour migration worldwide", "Restrictions on international trade", "The internet and mobile communication technologies"], "hint": "Think about what factors INCREASE globalisation — the answer is the option that REDUCES or BLOCKS it, not enables it.", "starter": "The answer is C because restrictions on international trade..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — Restrictions on international trade</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A is wrong</strong> — A reduction in shipping costs through bulk containerisation made it cheaper to transport goods across the world, directly contributing to increased globalisation.</li><li><strong>B is wrong</strong> — An increase in labour migration means more workers moving between countries, which is a defining feature of globalisation, not a barrier to it.</li><li><strong>D is wrong</strong> — The internet and mobile communication technologies have massively increased the speed and ease of global communication, enabling businesses to operate internationally and driving globalisation.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:6-3-globalisation:exam:e75d6451', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'exam', 'mcq', 1, '{"num": "Q3", "question": "Globalisation refers to:", "options": ["the financial data used to measure the success of a multinational company", "the interconnected nature of business activities across the world", "the interdependencies that underpin decision-making in a large organisation", "the relationships that exist between the functional areas of a business"], "hint": "Think about what ''global'' means — it is about the whole world and how businesses, people, and economies connect across international borders.", "starter": "The answer is B because globalisation is about..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — the interconnected nature of business activities across the world</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A is wrong</strong> — Financial data refers to performance measurement within a business; it has no connection to the definition of globalisation.</li><li><strong>C is wrong</strong> — Interdependencies in decision-making refers to internal organisational management within a single large company, not cross-border global activity.</li><li><strong>D is wrong</strong> — The relationships between functional areas (e.g. marketing and finance) is an internal business concept and has nothing to do with globalisation or international trade.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:6-3-globalisation:exam:459ef6bc', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'exam', 'mcq', 1, '{"num": "Q7", "question": "International branding requires a business to:", "options": ["advertise online", "ignore religious differences", "sell its goods in every country", "take account of cultural differences"], "hint": "Think about what a business must consider to make its brand work successfully across different countries and audiences.", "starter": "The answer is D because international branding means..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — take account of cultural differences</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A is wrong</strong> — Advertising online is just one communication channel. A business can have a strong international brand without advertising online, and online advertising is not a defining requirement of international branding.</li><li><strong>B is wrong</strong> — Ignoring religious differences would actively damage a brand internationally. Successful international branding requires sensitivity to both cultural AND religious differences, not ignoring them.</li><li><strong>C is wrong</strong> — A business does not need to sell in every single country to develop an international brand. International branding is about creating a consistent global image; a business could operate in just a handful of countries and still have an international brand.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:6-3-globalisation:exam:6459fced', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'exam', 'mcq', 1, '{"num": "Q10", "question": "A company operates in several countries.<br><br>This is an example of:", "options": ["a multinational organisation", "customer engagement", "international branding", "operations management"], "hint": "Think about what we call a business that has operations (not just sales) running in more than one country.", "starter": "The answer is A because a business that operates in several countries is defined as..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>A — a multinational organisation</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>B is wrong</strong> — Customer engagement refers to the ways a business interacts with its customers to build loyalty and relationships. It is not related to the geographic scope of a business''s operations.</li><li><strong>C is wrong</strong> — International branding is about creating a recognisable brand image that is promoted consistently across multiple countries. A company can have an international brand without operating in multiple countries, and can operate in multiple countries without a unified international brand.</li><li><strong>D is wrong</strong> — Operations management refers to the internal management of production processes and resources within a business. It does not describe a company operating across multiple countries.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:6-3-globalisation:mcq:3f1b3e6d', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "What is the correct definition of globalisation?", "options": ["The process by which a business expands its product range", "The process by which business activity across the world has become increasingly interconnected", "The process of a business setting up a new branch in a foreign country", "The process of removing taxes on goods produced in a single country"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Globalisation refers to the increasing interconnection of business activity worldwide — including trade, movement of people, and movement of capital across borders."}'::jsonb),
('business:6-3-globalisation:mcq:a1342437', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which of the following is a tariff?", "options": ["A limit on the amount of a good that can be imported", "A rule about the quality standard a product must meet", "A tax on a good or service that is imported", "A government subsidy given to domestic producers"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. A tariff is a tax placed on imported goods or services, making them more expensive and less competitive compared to domestically produced alternatives."}'::jsonb),
('business:6-3-globalisation:mcq:f9598aad', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "A quota is best described as:", "options": ["A tax applied to exports leaving a country", "A limit in terms of weight or value on the amount of a good that can be imported", "A government grant given to multinational companies", "A minimum wage level set for overseas workers"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. A quota restricts the volume or value of imports allowed into a country, protecting domestic industries from too much foreign competition."}'::jsonb),
('business:6-3-globalisation:mcq:4ee1b646', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which mnemonic helps students remember the effect of a strong pound on trade?", "options": ["SMART — Strong Money Affects Retail Trading", "FOREX — Foreign Exchange Reduces Exports", "SPICED — Strong Pound: Imports Cheaper, Exports Dearer", "TRADE — Tariffs Reduce All Domestic Earnings"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. SPICED stands for Strong Pound: Imports Cheaper, Exports Dearer. When the pound strengthens, UK exports become more expensive for foreign buyers, reducing competitiveness abroad."}'::jsonb),
('business:6-3-globalisation:mcq:6d01c549', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "What makes a company a multinational company (MNC)?", "options": ["It sells products to customers in more than one country", "It has an internationally recognised brand name", "It operates (has physical presence) in more than one country", "It is listed on a foreign stock exchange"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. An MNC is defined by where it operates — having factories, offices, or facilities in multiple countries. Simply selling abroad does not make a business a multinational."}'::jsonb),
('business:6-3-globalisation:mcq:655f0dea', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which of the following developments most helped reduce the cost of international shipping?", "options": ["The introduction of tariff-free zones", "The development of standardised containers", "The creation of the World Trade Organisation", "The expansion of free trade areas in Asia"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Standardised shipping containers revolutionised global trade by making it faster and cheaper to transfer goods between ships, lorries and trains, dramatically cutting logistics costs."}'::jsonb),
('business:6-3-globalisation:mcq:5a0b35a3', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "If the pound weakens against the euro, what is the most likely effect for a UK exporter?", "options": ["UK exports become more expensive for EU buyers, reducing sales", "UK exports become cheaper for EU buyers, potentially increasing sales", "UK imports become cheaper, improving profit margins", "The exchange rate has no effect on export competitiveness"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. A weaker pound means UK goods cost less in foreign currencies. This makes UK exports more competitively priced abroad, which can boost export sales."}'::jsonb),
('business:6-3-globalisation:mcq:c6f7bbea', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "International branding requires businesses to ''think global, act local''. What does this mean?", "options": ["Translate all advertising into every language", "Sell the same product at the same price globally", "Maintain core brand values worldwide but adapt the message for local cultures", "Only promote products in countries where average incomes are high"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. ''Think global, act local'' means a business maintains a consistent global brand identity (e.g. logo, core values) while adapting elements like language, imagery and promotions to suit local cultural and religious norms."}'::jsonb),
('business:6-3-globalisation:mcq:e2b0394d', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which of the following is a benefit of becoming a multinational for the host country?", "options": ["Profits are kept in the host country", "Local firms always grow stronger due to increased competition", "Jobs and tax revenues are created in the host country", "The host country''s currency always strengthens"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. MNCs bring jobs to host countries, increasing incomes and local spending. They also pay taxes which fund public services. However, profits are often repatriated to the home country."}'::jsonb),
('business:6-3-globalisation:mcq:908e8944', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "Raleigh Cycles moved production to Taiwan. Which factor best explains this decision?", "options": ["Proximity to major UK customers", "Lower labour and production costs abroad", "Better quality control near UK headquarters", "To avoid paying UK corporation tax"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Raleigh moved production to Taiwan primarily to reduce costs — wages and manufacturing costs were significantly lower there than in the UK, improving competitiveness."}'::jsonb),
('business:6-3-globalisation:mcq:80a8cfa6', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "What is free trade?", "options": ["Trade between businesses that do not charge customers", "The absence of barriers such as tariffs or quotas between countries", "A government scheme that subsidises domestic exporters", "Trade only conducted between countries with the same currency"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Free trade means trading between countries without barriers like tariffs, quotas or regulations. It is encouraged by organisations like the WTO and exists in areas like NAFTA and SAFTA."}'::jsonb),
('business:6-3-globalisation:mcq:368e9f9d', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'mcq', 'mcq', 1, '{"question": "Which of the following is a disadvantage of globalisation for a host country?", "options": ["Access to foreign investment and technology", "New job opportunities for local workers", "Profits sent back to the MNC''s home country, reducing local economic benefit", "Lower prices for consumers"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. A key drawback of MNCs in host countries is profit repatriation — where profits are transferred to the company''s home country headquarters rather than being reinvested locally, limiting economic benefit."}'::jsonb),
('business:6-3-globalisation:tf:e2319576', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "A tariff is a limit on the quantity of a good that can be imported."}'::jsonb, '{"answer": false, "explain": "FALSE. A tariff is a TAX on imported goods. A QUOTA is the limit on the quantity or value of imports. These are two different trade barriers."}'::jsonb),
('business:6-3-globalisation:tf:bcea65ab', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "A multinational company is defined as any business that sells products to customers in another country."}'::jsonb, '{"answer": false, "explain": "FALSE. A multinational company must OPERATE in more than one country — meaning it has physical facilities such as factories, offices or staff there. Simply selling abroad does not make a business multinational."}'::jsonb),
('business:6-3-globalisation:tf:87b4227e', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "When the pound strengthens against other currencies, UK exports become more expensive for foreign buyers."}'::jsonb, '{"answer": true, "explain": "TRUE. A stronger pound means foreign buyers need more of their currency to buy the same amount of pounds. This makes UK goods more expensive abroad, potentially reducing export sales — as summarised by SPICED."}'::jsonb),
('business:6-3-globalisation:tf:b12d2387', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "Free trade means there are no tariffs, quotas, or restrictions on trade between countries."}'::jsonb, '{"answer": true, "explain": "TRUE. Free trade is defined as the absence of barriers (tariffs, quotas, regulations) on international trade. Examples of free trade areas include NAFTA and SAFTA."}'::jsonb),
('business:6-3-globalisation:tf:7f2bb12e', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "International branding means a business sells its products in every country in the world."}'::jsonb, '{"answer": false, "explain": "FALSE. International branding means creating a brand image that is recognised and promoted across multiple countries — but a business does not need to sell everywhere to have an international brand."}'::jsonb),
('business:6-3-globalisation:tf:185bb6e6', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "One benefit for a host country when an MNC locates there is that jobs and tax revenues are created."}'::jsonb, '{"answer": true, "explain": "TRUE. MNCs create employment for local workers and pay taxes to the host government, helping to fund public services such as schools and hospitals."}'::jsonb),
('business:6-3-globalisation:tf:83c48f7a', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "When the pound weakens, UK imports become cheaper for domestic businesses."}'::jsonb, '{"answer": false, "explain": "FALSE. When the pound weakens, imports become MORE expensive because it costs more pounds to buy the same amount of foreign currency. A weaker pound makes exports cheaper, not imports."}'::jsonb),
('business:6-3-globalisation:tf:1fa2e83c', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "Containerisation has helped reduce the cost of international trade by standardising how goods are transported by sea."}'::jsonb, '{"answer": true, "explain": "TRUE. Standardised shipping containers can be loaded quickly between ships, lorries, and trains, dramatically cutting transport costs and boosting global trade volumes."}'::jsonb),
('business:6-3-globalisation:tf:7cb4fdab', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "Raleigh Cycles moved production back to the UK to take advantage of lower labour costs."}'::jsonb, '{"answer": false, "explain": "FALSE. Raleigh moved production TO Taiwan (abroad) to benefit from lower labour costs. Some production was later returned to the UK, but the initial move abroad was specifically to cut costs."}'::jsonb),
('business:6-3-globalisation:tf:4a425dc9', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "One risk of a multinational becoming too large is that it may face diseconomies of scale, becoming harder to manage efficiently."}'::jsonb, '{"answer": true, "explain": "TRUE. As MNCs grow very large and spread across many countries, coordination becomes complex, communication slows down, and management costs rise — all signs of diseconomies of scale."}'::jsonb),
('business:6-3-globalisation:tf:bb643768', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "After Brexit, UK businesses can now export to the EU with no additional paperwork or checks."}'::jsonb, '{"answer": false, "explain": "FALSE. Since January 2021, UK exports to the EU require additional documentation, health certificates, and border checks. Some businesses have had to stop exporting to the EU entirely due to these increased costs."}'::jsonb),
('business:6-3-globalisation:tf:8e99ee31', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'tf', 'tf', 1, '{"question": "The principle ''think global, act local'' means a business should sell identical products in every country without any adaptations."}'::jsonb, '{"answer": false, "explain": "FALSE. ''Think global, act local'' means maintaining a consistent global brand identity while ADAPTING the message, products, or promotions to suit local cultures, religions, and income levels in each market."}'::jsonb),
('business:6-3-globalisation:learn:cd293821', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "What is Globalisation?", "reading": "<p><strong>Globalisation</strong> is the process by which business activity around the world has become increasingly interconnected. It involves three key movements:</p>\n<ul>\n<li><strong>Trade:</strong> Buying and selling goods and services made in different countries.</li>\n<li><strong>People:</strong> The movement of workers from country to country.</li>\n<li><strong>Capital:</strong> The movement of money or assets (machines, buildings, vehicles) from country to country.</li>\n</ul>\n<p>Globalisation has increased at a rapid rate, driven by three major improvements:</p>\n<ul>\n<li><strong>Transport:</strong> Costs have fallen as ships and planes have grown bigger. The development of <strong>containers</strong> — standardised boxes lifted by crane from ship to lorry — has significantly reduced costs.</li>\n<li><strong>Telecommunications & the Internet:</strong> Communication is faster and cheaper. Businesses can research suppliers worldwide, order via email or video-conferencing, and promote products through websites and social media.</li>\n<li><strong>Free Trade Arrangements:</strong> <strong>Free trade</strong> exists when there are no barriers such as <strong>tariffs</strong> (taxes on imports), <strong>quotas</strong> (limits on the amount imported) or <strong>regulations</strong> (rules on goods that can be sold). The WTO encourages countries to remove these barriers. Examples of free trade areas include NAFTA (USA, Canada, Mexico) and SAFTA (South Asia).</li>\n</ul>", "question": "According to this card, what are the three key movements involved in globalisation?", "options": ["Trade, people, and capital movement", "Imports, exports, and exchange rates", "Branding, marketing, and advertising", "Tariffs, quotas, and regulations"]}'::jsonb, '{"answer": 0, "explain": "The card explains globalisation involves three key movements: trade (goods/services), people (workers), and capital (money and assets) between countries."}'::jsonb),
('business:6-3-globalisation:learn:ff63e0a9', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Key Terminology", "reading": "<ul>\n<li><strong>Globalisation:</strong> The process by which business activity around the world has become increasingly interconnected.</li>\n<li><strong>International Branding:</strong> Creating an image or values for a product that are communicated in countries around the world.</li>\n<li><strong>Free Trade:</strong> The absence of restrictions on trade between countries.</li>\n<li><strong>Tariff:</strong> A tax on a good or service that is imported.</li>\n<li><strong>Quota:</strong> A limit in terms of weight or value on the amount of a good or service that can be imported.</li>\n<li><strong>Regulations:</strong> Rules about the goods and services that can be sold in a country.</li>\n<li><strong>Multinational Company (MNC):</strong> A business that operates in different countries around the world.</li>\n<li><strong>Productivity:</strong> A measure of the output of each worker on average.</li>\n<li><strong>Unit Cost:</strong> The cost per unit produced. The greater the productivity of workers, the lower the unit cost.</li>\n<li><strong>Exchange Rate:</strong> The price of one currency in terms of another (e.g. £1 = €1.2).</li>\n</ul>", "question": "According to the key terminology, what is a ''quota''?", "options": ["A rule about the goods and services that can be sold in a country", "The price of one currency expressed in terms of another", "A limit on the weight or value of a good that can be imported", "A tax charged on a good or service that is imported"]}'::jsonb, '{"answer": 2, "explain": "The card defines a quota as a limit on the weight or value of a good that can be imported — distinct from a tariff (a tax) or a regulation (a rule)."}'::jsonb),
('business:6-3-globalisation:learn:f11e74ee', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Multinational Companies (MNCs)", "reading": "<p><strong>Multinational companies (MNCs)</strong> are businesses that operate in more than one country. They are a key feature of globalisation. Well-known examples include Google, Amazon, Coca-Cola, Starbucks and McDonald''s.</p>\n<p>There are several advantages to a <strong>business</strong> of becoming a multinational:</p>\n<ul>\n<li><strong>Increasing sales:</strong> Selling in more countries increases the size of the market and potential revenue.</li>\n<li><strong>Spreading risk:</strong> If one market suffers a recession, the company can compensate with sales growth in another country.</li>\n<li><strong>Lower costs:</strong> Production may be cheaper in another country due to lower wages, cheaper land, or better technology.</li>\n<li><strong>Tax avoidance:</strong> MNCs may set up headquarters in low-tax countries (e.g. Luxembourg or Ireland) to reduce their overall tax bill, even while selling in higher-tax countries.</li>\n</ul>", "question": "According to this card, why might a business become a multinational to reduce risk?", "options": ["Multinationals are legally protected from ever making a loss at all", "If one market suffers a recession, sales growth elsewhere can compensate", "Multinationals only ever sell their products in a single country at once", "Multinationals never have to pay any tax in any country they operate in"]}'::jsonb, '{"answer": 1, "explain": "The card lists spreading risk as an advantage of becoming multinational — if one market suffers a recession, growth in another market can compensate."}'::jsonb),
('business:6-3-globalisation:learn:2b3c463f', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Impact of MNCs on the Host Country", "reading": "<p>The country where a multinational locates is called the <strong>host country</strong>. MNCs bring both benefits and drawbacks to that country.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Advantages to Host Country</div>\n<div class=\"pro-item\"><strong>Creates demand for local businesses:</strong> MNCs employ local people, increasing incomes and local spending. They may also buy supplies from local firms.</div>\n<div class=\"pro-item\"><strong>Taxes & public services:</strong> Tax payments by MNCs help governments fund education, health and infrastructure.</div>\n<div class=\"pro-item\"><strong>Lower prices:</strong> By keeping costs low, MNCs may offer goods and services at cheaper prices for consumers and businesses.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Disadvantages to Host Country</div>\n<div class=\"con-item\"><strong>Business closures:</strong> Local firms may be unable to compete on price or quality and get forced out of business. MNCs may also pay higher wages, pulling workers away from local employers.</div>\n<div class=\"con-item\"><strong>Outflows of money:</strong> Profits are often sent back to the MNC''s home country headquarters, limiting the financial benefit to the host country.</div>\n<div class=\"con-item\"><strong>Diseconomies of scale:</strong> As MNCs grow very large, they can become harder to manage and less efficient.</div>\n</div>\n</div>\n<div class=\"case-study-box\">\n<h4>Case Study: Vodafone in the UK</h4>\n<p>Vodafone sells mobile and ICT services across many countries. Although headquartered in the UK, profits are routed to Luxembourg where taxation is much lower — a practice accused of being tax avoidance. Vodafone disputes this, arguing it pays all taxes legally owed and contributes through investment, job creation and over £1.2 billion spent on UK network upgrades. This case illustrates the debate around whether MNCs truly benefit host countries or exploit lower-tax loopholes.</p>\n</div>", "question": "According to the Vodafone case study, what practice is Vodafone accused of?", "options": ["Routing profits to Luxembourg, where taxation is much lower", "Selling all of its UK operations to a foreign competitor firm", "Employing no staff whatsoever within the United Kingdom itself", "Refusing to invest any money at all in UK network upgrades"]}'::jsonb, '{"answer": 0, "explain": "The card explains Vodafone routes profits to Luxembourg where taxation is lower — a practice accused of being tax avoidance, which Vodafone disputes."}'::jsonb),
('business:6-3-globalisation:learn:8f54dd36', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Influences on Business Location", "reading": "<p>Globalisation means businesses have greater freedom to choose <strong>where</strong> they locate production. A UK business may move production abroad — or bring it back home — for several reasons.</p>\n<p><strong>Reasons to locate ABROAD:</strong></p>\n<ul>\n<li><strong>Lower labour costs:</strong> Wages are much lower in many countries, especially in the Far East. This is why Raleigh Cycles moved production to Taiwan.</li>\n<li><strong>Lower technology costs:</strong> Some foreign firms have invested more in up-to-date manufacturing technology, reducing production costs.</li>\n<li><strong>Lower property/land costs:</strong> Factories and premises may be cheaper abroad.</li>\n<li><strong>Access to expertise:</strong> Businesses may locate near specialist skills or R&D talent in other countries.</li>\n<li><strong>Proximity to demand:</strong> Locating near the target market can increase sales. The Electric Car Corporation moved production to Denmark because demand for electric cars was stronger there.</li>\n</ul>\n<p><strong>Reasons to move production BACK to the UK:</strong></p>\n<ul>\n<li><strong>Quality control:</strong> It is easier to monitor standards when production is close to headquarters.</li>\n<li><strong>Communications:</strong> No language barriers or time zone differences with a UK workforce.</li>\n<li><strong>Skilled labour:</strong> The UK has a strong supply of skilled workers in many industries.</li>\n<li><strong>Consumer preference:</strong> Many UK customers prefer goods labelled ''Made in Britain''.</li>\n<li><strong>Environment:</strong> UK production reduces transport distances, lowering the business''s carbon footprint — a strong marketing point.</li>\n<li><strong>Rising foreign wages:</strong> As wages in developing countries increase, the cost advantage of producing abroad shrinks.</li>\n</ul>\n<div class=\"case-study-box\">\n<h4>Case Study: Raleigh Cycles</h4>\n<p>Raleigh, the famous Nottingham bicycle manufacturer, went bankrupt in the 2000s. New owners moved production to Taiwan and South East Asia to cut costs, while keeping sales, marketing and design in the UK. The business recovered strongly and has since moved some assembly back to Nottingham — showing that location decisions are not permanent and must be regularly reviewed.</p>\n</div>", "question": "According to the Raleigh Cycles case study, what does the company''s history show?", "options": ["Once a business moves abroad, it can never return production home", "Raleigh has never produced any bicycles outside of Nottingham at all", "Moving production abroad always causes a company to go bankrupt", "Location decisions are not permanent and must be regularly reviewed"]}'::jsonb, '{"answer": 3, "explain": "The card explains Raleigh moved production to Taiwan then moved some assembly back to Nottingham — showing location decisions must be regularly reviewed."}'::jsonb),
('business:6-3-globalisation:learn:040aa3c1', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "International Branding", "reading": "<p><strong>Branding</strong> refers to a product''s image, reputation and values — communicated through logos, words, images, music and media (TV, social media, websites). When selling globally, a business must adapt its branding to suit each country. The key principle is: <strong>\"Think global, act local\"</strong> — promote the same core values worldwide, but deliver the message differently in each market.</p>\n<p>Businesses must consider the following factors when creating an international brand:</p>\n<ul>\n<li><strong>Culture & Religion:</strong> Images or themes acceptable in one country may deeply offend in another. A Coca-Cola ad featuring Father Christmas would not work in a predominantly Muslim country like Pakistan.</li>\n<li><strong>Language:</strong> Product names, slogans and advertisements must be translated carefully. An American fast food company mistakenly advertised ''yassuppoi'' chips in Japan — meaning ''low quality'' in Japanese.</li>\n<li><strong>Names:</strong> Products sometimes need different names. Burger King operates as ''Hungry Jack''s'' in Australia because the Burger King name was already trademarked there.</li>\n<li><strong>Level & Distribution of Income:</strong> There is no point promoting a luxury product in a country where most people cannot afford it. Businesses must research average incomes and how evenly wealth is spread.</li>\n<li><strong>Legal Factors:</strong> Businesses must follow local advertising laws. Alcohol advertising is illegal in Sri Lanka; cigarettes are banned entirely in Bhutan.</li>\n<li><strong>Bribery:</strong> In some countries, bribery is commonplace in business dealings. In the UK it is illegal and carries serious reputational and legal consequences.</li>\n</ul>\n<div class=\"case-study-box\">\n<h4>Case Study: McDonald''s in India</h4>\n<p>McDonald''s adapts its products to suit local cultures. In India, where beef is not eaten for religious reasons, the Big Mac is made from chicken and marketed as the ''Maharajah Mac'' (meaning king-size burger). Prices are also lower — around £1.97 compared to £3.25 in the UK — to reflect lower average incomes. This shows how the 4 Ps (Product, Price, Promotion, Place) must all be adapted for international markets.</p>\n</div>", "question": "According to the McDonald''s in India case study, how did McDonald''s adapt its product?", "options": ["It charged higher prices in India than in the UK for the same burger", "It made the Big Mac from chicken instead of beef, for religious reasons", "It refused to sell any burgers at all within the Indian market", "It kept the exact same product and price as in every other country"]}'::jsonb, '{"answer": 1, "explain": "The card explains McDonald''s made the ''Maharajah Mac'' from chicken (since beef is not eaten for religious reasons in India) and priced it lower than the UK Big Mac."}'::jsonb),
('business:6-3-globalisation:learn:befecff2', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "How Businesses Compete Internationally", "reading": "<p>Competing internationally means both selling abroad and competing against foreign firms at home. Businesses must adapt across all areas of the organisation:</p>\n<ul>\n<li><strong>Growth:</strong> Businesses may expand organically (e.g. Marks & Spencer opening shops across the world) or through joint ventures (e.g. Jaguar Land Rover partnering with Chery in China to produce and sell cars without import tariffs).</li>\n<li><strong>Marketing (4 Ps):</strong> Products may need to be changed (e.g. JLR makes longer wheelbase cars for Chinese buyers); prices adjusted for local incomes; promotions must reflect local culture; and place decisions must consider whether to be near customers or raw materials.</li>\n<li><strong>Human Resources:</strong> Businesses must recruit and train overseas workers, comply with local employment laws, and find suitable ways to motivate staff in different cultural contexts.</li>\n<li><strong>Business Operations:</strong> Methods of production may need to change — switching from job to batch production to cut costs. Quality assurance processes must be put in place if producing abroad.</li>\n<li><strong>Finance:</strong> International expansion requires sources of finance for investment. Break-even analysis helps businesses assess whether selling in a new country will be profitable.</li>\n<li><strong>Ethical & Environmental:</strong> Businesses must consider the ethical implications of producing in countries with weaker labour laws or environmental standards. Negative publicity (e.g. Primark and child labour accusations) can damage a brand significantly.</li>\n</ul>", "question": "According to this card, why did Jaguar Land Rover form a joint venture with Chery in China?", "options": ["To stop selling any of its cars within the United Kingdom market", "To avoid ever having to adapt its products for Chinese buyers", "To prevent Chinese customers from being able to buy its cars", "To produce and sell cars in China without paying import tariffs"]}'::jsonb, '{"answer": 3, "explain": "The card explains JLR partnered with Chery in China to produce and sell cars there without import tariffs, while also adapting products like longer wheelbase cars."}'::jsonb),
('business:6-3-globalisation:learn:39585cea', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Exchange Rates & International Competitiveness", "reading": "<p>The <strong>exchange rate</strong> is the price of one currency in terms of another (e.g. £1 = €1.20). Changes in the exchange rate directly affect the price of exports and imports, and therefore a business''s competitiveness abroad.</p>\n<p>A useful mnemonic to remember the effects is <strong>SPICED</strong>:</p>\n<div class=\"formula-box\">\n<strong>SPICED</strong> = Strong Pound → Imports Cheaper, Exports Dearer\n</div>\n<ul>\n<li><strong>If the pound rises (strengthens):</strong> Exports become more expensive for foreign buyers (likely to reduce export sales). Imports become cheaper for UK businesses (good for importers, but harder for domestic producers to compete).</li>\n<li><strong>If the pound falls (weakens):</strong> Exports become cheaper for foreign buyers (likely to increase export sales). Imports become more expensive (raises costs for UK firms that rely on imported materials).</li>\n</ul>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Weak Pound — Good For</div>\n<div class=\"pro-item\"><strong>Exporters:</strong> Their goods become cheaper abroad, increasing overseas sales. Brandauer, a Birmingham engineering firm, saw export sales rise after the pound fell following Brexit.</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Weak Pound — Bad For</div>\n<div class=\"con-item\"><strong>Importers:</strong> Imported raw materials and components become more expensive, pushing up production costs. Princess Yachts noted costs rose as imported components became pricier after the pound fell.</div>\n</div>\n</div>\n<div class=\"case-study-box\">\n<h4>Case Study: Princess Yachts</h4>\n<p>Princess Yachts, based in Plymouth, sells 80% of its yachts abroad. After the pound fell in value, exports became cheaper for overseas buyers and sales increased. However, costs also rose slightly as some imported components became more expensive. This illustrates that exchange rate changes rarely have a simple, one-sided effect — businesses that both import and export must weigh up the overall impact carefully.</p>\n</div>", "question": "According to the SPICED mnemonic in this card, what happens when the pound is strong?", "options": ["Both imports and exports become cheaper at the same time", "Imports become dearer and exports become cheaper", "Imports become cheaper and exports become dearer", "Both imports and exports become dearer at the same time"]}'::jsonb, '{"answer": 2, "explain": "The SPICED mnemonic states: Strong Pound leads to Imports Cheaper, Exports Dearer — the reverse happens when the pound weakens."}'::jsonb),
('business:6-3-globalisation:learn:810f1640', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'learn', 'mcq', 1, '{"readingTitle": "Brexit & Its Impact on UK Businesses", "reading": "<p>The UK officially left the European Union in January 2020. Since 1 January 2021, new trading rules have applied. Brexit has had both negative and positive effects on UK businesses.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✗ Negative Effects</div>\n<div class=\"con-item\"><strong>New paperwork & inspections:</strong> UK exports to the EU must now meet EU standards and be accompanied by documentation. This costs time and money, and border delays have slowed deliveries. Some UK firms have stopped trading with the EU entirely.</div>\n<div class=\"con-item\"><strong>Labour shortages:</strong> Freedom of movement has ended. EU workers must now apply for the right to work in the UK. Restaurant chains like D&D London (43 restaurants) have struggled to recruit skilled chefs as a result.</div>\n<div class=\"con-item\"><strong>Rules of origin:</strong> UK-made goods must use a minimum proportion of British components to qualify as ''Made in the UK'' when exporting to the EU.</div>\n<div class=\"con-item\"><strong>Northern Ireland complications:</strong> Goods moving from the rest of the UK to Northern Ireland are treated as exports to the EU, requiring extra checks.</div>\n</div>\n<div>\n<div class=\"col-head\">✓ Positive Effects</div>\n<div class=\"pro-item\"><strong>New trade deals:</strong> The UK is now free to negotiate independently with non-EU countries. A deal with Japan already makes 99% of UK exports to Japan tariff-free.</div>\n<div class=\"pro-item\"><strong>Weaker pound boosts exports:</strong> The fall in the pound''s value after Brexit made UK exports cheaper. Brandauer (Birmingham) increased EU exports of precision-engineered components as a result.</div>\n<div class=\"pro-item\"><strong>Some inward investment:</strong> Nissan announced over £1 billion of investment to expand electric car production in Sunderland after the Brexit free-trade deal was secured.</div>\n</div>\n</div>\n<div class=\"case-study-box\">\n<h4>Case Study: The Cheshire Cheese Company</h4>\n<p>Before Brexit, the Cheshire Cheese Company exported cheese to the EU with no tariffs and no additional paperwork. After Brexit, each export now requires a health certificate costing £180 — even for a gift package worth just £30. The owner estimated a loss of revenue of up to £250,000. This illustrates how non-tariff barriers (like certificates and inspections) can be just as damaging as tariffs for small exporters.</p>\n</div>", "question": "According to the Cheshire Cheese Company case study, what changed after Brexit?", "options": ["Tariffs on cheese exports to the EU were removed entirely", "Exports to the EU became completely free of any paperwork", "Each export now requires a health certificate costing £180", "The company was banned from exporting any cheese at all"]}'::jsonb, '{"answer": 2, "explain": "The card explains that after Brexit each export now requires a £180 health certificate, even for a small gift package — a non-tariff barrier that damaged the business."}'::jsonb),
('business:6-3-globalisation:misc:4f349608', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A business that sells products to customers abroad is automatically a multinational company.</p><p><strong>✅ The correct idea:</strong> A multinational company must OPERATE in more than one country — having physical facilities, staff, or offices there. Simply exporting goods abroad does not make a business a multinational. The examiner''s report specifically warned against this confusion.</p>", "question": "Does selling products to customers abroad automatically make a business a multinational?", "options": ["Yes — but only if the business sells to more than ten different countries", "No — but only because multinationals are not allowed to export goods", "Yes — any business that exports goods abroad is automatically a multinational", "No — a multinational must physically operate in more than one country"]}'::jsonb, '{"answer": 3, "explain": "The card explains a multinational must OPERATE in more than one country with facilities or staff — simply exporting goods abroad does not make a business a multinational."}'::jsonb),
('business:6-3-globalisation:misc:7958aad7', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> International branding, international trade, and multinational company all mean the same thing.</p><p><strong>✅ The correct idea:</strong> These are three completely different concepts. International branding = creating a consistent brand image across countries. International trade = buying/selling across borders. Multinational company = physically operating in multiple countries. Confusing them will cost marks in every question.</p>", "question": "Are international branding, international trade, and multinational company the same concept?", "options": ["No — but only multinational and international trade mean the same thing", "Yes — but only international trade and branding are the same thing", "Yes — all three terms describe exactly the same business activity", "No — they are three completely different business concepts entirely"]}'::jsonb, '{"answer": 3, "explain": "The card explains these are three completely different concepts — branding is image, trade is buying/selling, and multinational means physically operating abroad."}'::jsonb),
('business:6-3-globalisation:misc:0aae806e', 'business', 'business:6-3-globalisation', '6.3 Globalisation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A tariff and a quota are the same type of trade barrier.</p><p><strong>✅ The correct idea:</strong> A tariff is a TAX on imported goods, making them more expensive. A quota is a LIMIT on the quantity or value of goods that can be imported. They are different tools with different mechanisms.</p>", "question": "What is the key difference between a tariff and a quota?", "options": ["A quota is a tax on imports, while a tariff is a limit on import quantity", "A tariff and a quota are simply two different names for the same tool", "A tariff is a tax on imports, while a quota is a limit on import quantity", "A tariff only applies to exports, while a quota only applies to imports"]}'::jsonb, '{"answer": 2, "explain": "The card explains a tariff is a TAX on imported goods, while a quota is a LIMIT on the quantity or value that can be imported — different tools entirely."}'::jsonb)
